SELECT AVG(test_scores) AS average_test_score
FROM performance_metrics
WHERE sid = 1 AND semester_id = 1;

SELECT sid, semester_id, test_scores, project_scores, feedback
FROM performance_metrics
WHERE semester_id = 1 AND sid = 1;

SELECT first_name || ' ' || last_name AS student_name
FROM students
ORDER BY first_name, last_name;

SELECT first_name, last_name 
FROM students 
ORDER BY first_name, last_name;
